import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjListView } from "./OjListView";
export { OjListView };

/**
 * Create an instance of [[OjListView]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojListView(driver, By.id('my-oj-list-view'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojListView(driver: DriverLike, by: By): Promise<OjListView> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjListView
  if (!(webEl instanceof OjListView)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-list-view>`);
  }
  return webEl;
}

register("oj-list-view", OjListView);
